package io.scanbot.barcodesdk.plugin.reactnative

import com.facebook.react.bridge.Promise
import io.scanbot.barcodesdk.plugin.reactnative.extensions.toWritableMap
import io.scanbot.sdk_wrapper.interfaces.SBResultDelegate
import org.json.JSONObject

class ScanbotBarcodeSdkPluginResultDelegate(
    private val promise: Promise?
) : SBResultDelegate {

    override fun didResolvePromise(resultAsJSON: JSONObject) {
        try {
            promise?.resolve(resultAsJSON.toWritableMap())
        } catch (ex: Exception) {
            promise?.reject(ex)
        }
    }

    override fun didRejectPromise(errorAsJSON: JSONObject) {
        promise?.reject("", Exception(errorAsJSON.getString("message")))
    }
}
